{
  "model": "{{ $env.OLLAMA_MODEL || 'qwen2.5:7b-instruct' }}",
  "prompt": "Kamu adalah expert content creator YouTube dan media sosial Indonesia.
Topik utama: {{ $('Normalize Request').first().json.title }}
Deskripsi: {{ $('Normalize Request').first().json.prompt }}
Kategori: {{ $('Normalize Request').first().json.category }}
Style visual: {{ $('Normalize Request').first().json.style }}
Mood: {{ $('Normalize Request').first().json.mood }}
Jumlah klip: {{ $('Normalize Request').first().json.clipCount }}
Durasi per klip: {{ $('Normalize Request').first().json.clipDuration }} detik

Buat output JSON valid (HANYA JSON, tidak ada teks lain):
{
  "narasi": "[naskah narasi lengkap minimal 1500 kata, hook kuat 30 detik pertama]",
  "video_prompts": ["deskripsi visual Bahasa Inggris per klip"],
  "judul": ["judul YouTube menarik", "alternatif 2", "alternatif 3"],
  "judul_tiktok": "judul TikTok max 100 karakter",
  "caption_facebook": "caption Facebook 50-80 kata",
  "deskripsi": "deskripsi YouTube 150-200 kata + hashtag",
  "tags": ["tag1","tag2","tag3","tag4","tag5"],
  "thumbnail_prompt": "deskripsi thumbnail YouTube 16:9"
}",
  "stream": false,
  "format": "json",
  "options": { "temperature": 0.8, "num_predict": 8192 }
}

parameters.jsCode:
const resp = $input.first().json;
const raw = resp?.response || resp?.message?.content || '';
const prev = $('Normalize Request').first().json;

let parsed;
try {
  const match = raw.match(/\{[\s\S]*\}/);
  parsed = JSON.parse(match ? match[0] : raw);
} catch(e) {
  console.error('[Parse Ollama] Gagal parse JSON:', e.message);
  parsed = {
    narasi: `Konten informatif tentang: ${prev.prompt}`,
    video_prompts: Array(prev.clipCount).fill(`${prev.style}, ${prev.mood}, high quality 4K cinematic`),
    judul: [`${prev.title} — Fakta Lengkap`],
    judul_tiktok: `${prev.title}`.substring(0, 100),
    caption_facebook: `${prev.title} — konten edukasi berkualitas. Bagikan ke temanmu!`,
    deskripsi: `Video tentang ${prev.title}. Subscribe untuk konten berkualitas! #edukasi #Indonesia`,
    tags: ['edukasi', 'fakta', 'viral', 'indonesia', 'trending', 'youtube', 'shorts'],
    thumbnail_prompt: `Bold YouTube thumbnail about ${prev.title}, shocked expression, high saturation, 16:9`
  };
}

const videoPrompts = Array.isArray(parsed.video_prompts)
  ? parsed.video_prompts.slice(0, prev.clipCount)
  : Array(prev.clipCount).fill(`${prev.style}, cinematic, high quality`);

return [{ json: {
  ...prev,
  narasi: parsed.narasi || '',
  video_prompts: videoPrompts,
  judul: Array.isArray(parsed.judul) ? parsed.judul[0] : (parsed.judul || prev.title),
  judul_tiktok: (parsed.judul_tiktok || parsed.judul?.[0] || prev.title).substring(0, 100),
  caption_facebook: parsed.caption_facebook || parsed.deskripsi || prev.title,
  deskripsi: parsed.deskripsi || '',
  tags: Array.isArray(parsed.tags) ? parsed.tags : [],
  thumbnail_prompt: parsed.thumbnail_prompt || '',
  ollama_ok: true
}}];

const prev = $input.first().json;
const narasiB64 = Buffer.from(prev.narasi || '', 'utf-8').toString('base64');
const promptsB64 = Buffer.from(JSON.stringify(prev.video_prompts || []), 'utf-8').toString('base64');
return [{ json: { ...prev, narasiB64, promptsB64 } }];

const stdout = $input.first().json.stdout || '';
const prev = $('Encode Base64').first().json;

const ttsOk = stdout.includes('TTS_OK');
const audioPath = stdout.match(/AUDIO_PATH:(.+)/)?.[1]?.trim() || prev.narasiPath;
const audioDuration = parseFloat(stdout.match(/AUDIO_DURATION:([\d.]+)/)?.[1] || '0');

if (!ttsOk) {
  console.error('[TTS] Gagal:', $input.first().json.stderr || stdout);
}

return [{ json: {
  ...prev,
  audio_ok: ttsOk,
  audio_path: audioPath,
  audio_duration: audioDuration
}}];

const stdout = $input.first().json.stdout || '';
const prev = $('Cek TTS').first().json;

const ffmpegOk = stdout.includes('FFMPEG_OK');
const finalDur = parseFloat(stdout.match(/FINAL_DURATION:([\d.]+)/)?.[1] || '0');
const finalSize = stdout.match(/FINAL_SIZE:(.+)/)?.[1]?.trim() || 'unknown';
const mins = Math.floor(finalDur / 60);
const secs = Math.floor(finalDur % 60);

if (!ffmpegOk) {
  console.error('[FFmpeg] Gagal:', $input.first().json.stderr || stdout);
  throw new Error('[FFmpeg] Assembly video gagal. Cek log Execute Command.');
}

return [{ json: {
  ...prev,
  ffmpeg_ok: ffmpegOk,
  final_duration: finalDur,
  final_duration_str: `${mins}m ${secs}s`,
  final_size: finalSize
}}];

const stdout = $input.first().json.stdout || '';
const prev = $('Parse Hasil FFmpeg').first().json;

let results = {};
try {
  const match = stdout.match(/UPLOAD_RESULTS:(\{[\s\S]*\})/);
  if (match) results = JSON.parse(match[1]);
} catch(e) {
  console.error('[Upload Parse] Error:', e.message, stdout);
}

const youtubeUrl = results.youtube?.url || '';
const tiktokOk = results.tiktok?.ok || false;
const facebookOk = results.facebook?.ok || false;
const tiktokVideoId = results.tiktok?.video_id || '';
const facebookPostId = results.facebook?.post_id || '';

const uploadSummary = [];
if (youtubeUrl) uploadSummary.push(`YouTube: ${youtubeUrl}`);
if (tiktokOk) uploadSummary.push(`TikTok: ${tiktokVideoId}`);
if (facebookOk) uploadSummary.push(`Facebook: ${facebookPostId}`);

return [{ json: {
  ...prev,
  youtubeUrl,
  tiktokOk,
  facebookOk,
  tiktokVideoId,
  facebookPostId,
  uploadResults: results,
  uploadSummary
}}];

